}

impl<'a> Processor<'a> {
    fn process_and_return(&self) -> Option<&'a str> {
        println!("Processing input: {}", self.input);
        if self.input.contains("critical") {
            Some(self.input)
        } else {
            None
        }
    }
}

fn main() {
    let original_string = String::from("This is the source data");
    let boxed_ref: &'static str = "Static reference";

    // Demonstrating lifetime in a struct method return
    { 
        let processor = Processor { input: &original_string };
        if let Some(result) = processor.process_and_return() {
            println!("Successfully obtained result reference: {}", result);
        }
