fn find_shorter(original: &str, short: &str) -> Option<String> {
    let original_len = original.chars().count();
    let short_len = short.chars().count();

    if original_len < short_len {
        Some(original.to_string())
    } else if short_len < original_len {
        Some(short.to_string())
    } else {
        None
    }
}

fn main() {
    let original_text = String::from("This is some long piece of writing.");
    let short_text = String::from("Shorty");

    let result = find_shorter(&original_text, &short_text);

    match result {
        Some(s) => println!("The shorter text is: {}", s),
        None => println!("Could not determine the shorter text.")
    }
}

struct Pair<'a, 'b> {
    first: &'a str,
    second: &'b str,
}

impl<'a, 'b> Pair<'a, 'b> {
    fn new(first: &'a str, second: &'b str) -> Self {
        Pair { first, second }
    }

    // This method signature requires the lifetime of the returned value 
    // to be tied to the lifetimes of its inputs.
    fn get_combined_info(&self) -> &'a str {
        // In a real scenario, this might return a pointer derived from self.first,
        // but for demonstration, we just use one of the stored references.
        self.first
    }
}

fn main() {
    let original_string = String::from("Hello World");
    let first_part: &'static str = "";
    let second_part: &'static str = "";

    // We create a Pair that borrows from the stack-allocated string and static strings.
    let combined = Pair::new(first_part, second_part);

    // The compiler ensures that any use of 'combined' or its derived info 
    // respects the initial lifetimes given to the struct.
    let result: &'static str = combined.get_combined_info();

    println!("Successfully handled combined data reference: {}", result);
}

struct ReferenceWrapper<'a> {
    data: &'a str,
}

impl<'a> ReferenceWrapper<'a> {
    fn new(source_data: &'a str) -> Self {
        ReferenceWrapper { data: source_data }
    }

    fn get_reference(&self) -> &'a str {
        self.data
    }
}

fn main() {
    let original_string = "Hello World";

    let wrapper = ReferenceWrapper::new(original_string);

    let borrowed_value = wrapper.get_reference();
    println!("The wrapped value is: {}", borrowed_value);
}

